const raw = ($json.body.sid || "").trim();
const urlMatch = raw.match(/\/orgs\/([A-Z0-9_-]+)/i);
const sid = urlMatch ? urlMatch[1].toUpperCase() : raw.toUpperCase().replace(/[^A-Z0-9_-]/g, "");
if (!sid) throw new Error("sid is required");
return [{ json: { sid } }];

const sid = $('Build Lookup SQL').first().json.sid;
const dbRow = $('DB Lookup Org').first().json;
const inDb = dbRow.in_db === true || dbRow.in_db === 't' || dbRow.in_db === 'true';
const rsiResp = $('RSI Org Page Check').first().json || {};
const rsiStatus = rsiResp.statusCode;
const html = rsiResp.data || rsiResp.body || '';
const rsiExists = rsiStatus === 200 && html.length > 1000;
var rsiOrg = null;
if (rsiExists) {
  var nameMatch = html.match(/<h1>([^\/<\n]+?)\s*\/\s*<span class="symbol">/i);
  var logoMatch = html.match(/class="logo[^"]*">\s*<img src="([^"]+)"/i);
  var countMatch = html.match(/class="count">(\d+)\s*members/i);
  var is_recruiting = html.indexOf('js-orgs-apply') !== -1;
  var descMatch = html.match(/class="body markitup-text">([\s\S]{0,2000}?)<\/div>/i);
  var archMatch = html.match(/class="model">([^<]+)/i);
  rsiOrg = { name: nameMatch ? nameMatch[1].trim() : null, logo_url: logoMatch ? 'https://robertsspaceindustries.com' + logoMatch[1] : null, member_count: countMatch ? parseInt(countMatch[1]) : null, is_recruiting, description: descMatch ? descMatch[1].replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim().substring(0,500) : null, archetype: archMatch ? archMatch[1].trim() : null };
}
const org = inDb ? { org_id: dbRow.org_id, slug: dbRow.slug, name: dbRow.name, description: dbRow.description, logo_url: dbRow.logo_url, rsi_url: dbRow.rsi_url, site_url: dbRow.site_url, discord_invite: dbRow.discord_invite, is_visible: dbRow.is_visible, is_recruiting: dbRow.is_recruiting, source: dbRow.source, member_count: dbRow.member_count } : null;
return [{ json: { sid, in_db: inDb, rsi_exists: rsiExists, org, rsi_org: rsiOrg } }];

const syncBody = $('Sync Webhook').first().json.body;
const userId = syncBody.user_id;
const resp = $input.first().json || {};
const statusCode = resp.statusCode;
const html = resp.data || resp.body || '';
const hasOrgsSection = html.indexOf('orgs-content') !== -1;
const rsiBlocked = statusCode !== 200 || !hasOrgsSection;
const orgs = [];
if (!rsiBlocked) {
  const parts = html.split('<div class="box-content org ');
  for (var i = 1; i < parts.length; i++) {
    var block = parts[i];
    var isMain = /^main[\s"]/i.test(block);
    var sidMatch = block.match(/href="\/orgs\/([A-Z0-9_-]+)"/i);
    if (!sidMatch) continue;
    var sid = sidMatch[1].toUpperCase();
    var nameMatch = block.match(/href="\/orgs\/[^"]+"\ class="[^"]*value[^"]*">([^<]+)<\/a>/i);
    var name = nameMatch ? nameMatch[1].trim() : sid;
    var rankMatch = block.match(/Organization rank[\s\S]{0,500}?<strong[^>]*>([^<]+)<\/strong>/i);
    var rank = rankMatch ? rankMatch[1].trim() : 'member';
    var logoMatch = block.match(/<img src="([^"]+)"\s*\/>/i);
    var logo_url = logoMatch ? 'https://robertsspaceindustries.com' + logoMatch[1] : null;
    var is_recruiting = block.indexOf('js-orgs-apply') !== -1;
    orgs.push({ slug: sid, name: name, logo_url: logo_url, is_main_org: isMain, org_role: rank, is_recruiting: is_recruiting });
  }
}
function esc(s) { return String(s).replace(/'/g, "''"); }
var orgsJson = JSON.stringify(orgs).replace(/'/g, "''");
return [{ json: { sql: "SELECT * FROM sync_user_orgs('" + userId + "'::uuid, '" + orgsJson + "'::jsonb)", rsi_blocked: rsiBlocked, org_count: orgs.length } }];

const dbResult = $('DB Sync User Orgs').first().json;
const parseResult = $('Parse Orgs and Build SQL').first().json;
return [{ json: { org_count: dbResult.org_count ?? 0, new_orgs: dbResult.new_orgs ?? 0, rsi_blocked: parseResult.rsi_blocked } }];

const userId = ($json.query?.user_id || '').trim();
if (!userId) throw new Error('user_id is required');
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(userId)) { throw new Error('user_id must be a valid UUID'); }
return [{ json: { user_id: userId } }];

const row = $input.first().json;
const orgs = row.orgs;
const parsed = typeof orgs === 'string' ? JSON.parse(orgs) : (orgs ?? []);
return [{ json: { orgs: Array.isArray(parsed) ? parsed : [] } }];

const body = $json.body;
const slug = (body.sid || '').toUpperCase().replace(/[^A-Z0-9_-]/g, '');
if (!slug) throw new Error('sid is required');
function esc(s) { return s ? String(s).replace(/'/g, "''") : null; }
const name = esc(body.name);
const description = esc(body.description);
const logo_url = esc(body.logo_url);
const rsi_url = esc(body.rsi_url) || ('https://robertsspaceindustries.com/orgs/' + slug);
const site_url = esc(body.site_url);
const discord_invite = esc(body.discord_invite);
const is_recruiting = body.is_recruiting === true ? 'true' : 'false';
const member_count = (body.member_count != null && !isNaN(parseInt(body.member_count))) ? parseInt(body.member_count) : null;
const v = (s) => s ? "'" + s + "'" : 'NULL';
const mc = member_count != null ? String(member_count) : 'NULL';
const sql = "INSERT INTO sc_orgs (slug, name, description, logo_url, rsi_url, site_url, discord_invite, is_visible, is_recruiting, member_count, source) VALUES ('" + slug + "', " + v(name) + ", " + v(description) + ", " + v(logo_url) + ", '" + rsi_url + "', " + v(site_url) + ", " + v(discord_invite) + ", true, " + is_recruiting + ", " + mc + ", 'manual') ON CONFLICT (slug) DO UPDATE SET name = COALESCE(EXCLUDED.name, sc_orgs.name), description = COALESCE(EXCLUDED.description, sc_orgs.description), logo_url = COALESCE(EXCLUDED.logo_url, sc_orgs.logo_url), rsi_url = EXCLUDED.rsi_url, site_url = COALESCE(EXCLUDED.site_url, sc_orgs.site_url), discord_invite = COALESCE(EXCLUDED.discord_invite, sc_orgs.discord_invite), is_visible = true, is_recruiting = EXCLUDED.is_recruiting, member_count = COALESCE(EXCLUDED.member_count, sc_orgs.member_count), source = 'manual', updated_at = NOW() RETURNING org_id, slug";
return [{ json: { slug, sql } }];

const body = $json.body;
const slug = (body.slug || '').toUpperCase().replace(/[^A-Z0-9_-]/g, '');
if (!slug) throw new Error('slug is required');
function esc(s) { return s != null ? String(s).replace(/'/g, "''") : null; }
const sets = [];
if ('name' in body) sets.push('name = ' + (body.name ? "'" + esc(body.name) + "'" : 'NULL'));
if ('description' in body) sets.push('description = ' + (body.description ? "'" + esc(body.description) + "'" : 'NULL'));
if ('logo_url' in body) sets.push('logo_url = ' + (body.logo_url ? "'" + esc(body.logo_url) + "'" : 'NULL'));
if ('rsi_url' in body) sets.push('rsi_url = ' + (body.rsi_url ? "'" + esc(body.rsi_url) + "'" : 'NULL'));
if ('site_url' in body) sets.push('site_url = ' + (body.site_url ? "'" + esc(body.site_url) + "'" : 'NULL'));
if ('discord_invite' in body) sets.push('discord_invite = ' + (body.discord_invite ? "'" + esc(body.discord_invite) + "'" : 'NULL'));
if ('is_visible' in body) sets.push('is_visible = ' + (body.is_visible ? 'true' : 'false'));
if ('is_recruiting' in body) sets.push('is_recruiting = ' + (body.is_recruiting ? 'true' : 'false'));
if ('member_count' in body) sets.push('member_count = ' + (body.member_count != null ? parseInt(body.member_count) : 'NULL'));
if (sets.length === 0) throw new Error('No fields to update');
sets.push('updated_at = NOW()');
const sql = 'UPDATE sc_orgs SET ' + sets.join(', ') + " WHERE slug = '" + slug + "' RETURNING org_id, slug, name, is_visible, is_recruiting";
return [{ json: { slug, sql } }];

const dbRow = $input.first().json;
if (!dbRow.slug) return [{ json: { ok: false, error: 'Org not found' } }];
return [{ json: { ok: true, org_id: dbRow.org_id, slug: dbRow.slug, name: dbRow.name, is_visible: dbRow.is_visible, is_recruiting: dbRow.is_recruiting } }];

const row = $input.first().json;
const orgs = row.orgs;
const parsed = typeof orgs === 'string' ? JSON.parse(orgs) : (orgs ?? []);
return [{ json: { orgs: Array.isArray(parsed) ? parsed : [] } }];

const body = $json.body || {};
const rawSlug = typeof body.slug === 'string' ? body.slug.trim().toUpperCase().replace(/[^A-Z0-9_-]/g, '') : '';
function esc(s) { return String(s).replace(/'/g, "''"); }
if (!rawSlug) {
  return [{ json: { valid: false, slug: '', sql: "SELECT NULL AS slug WHERE false" } }];
}
const safeSlug = esc(rawSlug);
const sql = "WITH target AS (SELECT org_id, slug FROM sc_orgs WHERE slug = '" + safeSlug + "'), clear_manager AS (UPDATE users SET managed_org_id = NULL WHERE managed_org_id IN (SELECT org_id FROM target) RETURNING 1), clear_members AS (DELETE FROM user_orgs WHERE org_id IN (SELECT org_id FROM target) RETURNING 1) DELETE FROM sc_orgs WHERE org_id IN (SELECT org_id FROM target) RETURNING slug";
return [{ json: { valid: true, slug: rawSlug, sql } }];

const items = $input.all();
const buildSql = $('Build Delete Org SQL').first().json;
const deleted = items.length > 0 && items[0].json && items[0].json.slug;
if (deleted) {
  return [{ json: { ok: true, slug: items[0].json.slug } }];
} else if (!buildSql.slug) {
  return [{ json: { ok: false, error: 'slug is required' } }];
} else {
  return [{ json: { ok: false, error: 'Org not found' } }];
}
